```java
package com.ktu.smarthome;

import android.content.Intent;
import android.os.Bundle;
import android.widget.SeekBar;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;
import com.ktu.smarthome.model.Sensor;
import java.util.ArrayList;

public class RoomControlActivity extends AppCompatActivity {

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_room_control);

        TextView tvRoom = findViewById(R.id.tvRoomName);
        TextView tvSensors = findViewById(R.id.tvSensors);
        SeekBar seekFan = findViewById(R.id.seekFanSpeed);

        Intent intent = getIntent();
        String roomName = intent.getStringExtra("ROOM_NAME");
        ArrayList<Sensor> sensors = intent.getParcelableArrayListExtra("ROOM_SENSORS");

        tvRoom.setText("Controlling: " + roomName);
        StringBuilder sb = new StringBuilder();
        if (sensors != null) {
            for (Sensor s : sensors) {
                sb.append(s.getName()).append(" (").append(s.getType()).append("): ")
                  .append(s.getCurrentValue()).append("\n");
            }
        }
        tvSensors.setText(sb.toString());

        seekFan.setMax(5);
        seekFan.setOnSeekBarChangeListener(new SeekBar.OnSeekBarChangeListener() {
            @Override
            public void onStopTrackingTouch(SeekBar seekBar) {
                int fanSpeed = seekBar.getProgress();
                Intent result = new Intent();
                result.putExtra("FAN_SPEED", fanSpeed);
                setResult(RESULT_OK, result);
                finish();
            }
            @Override public void onProgressChanged(SeekBar s, int p, boolean u) {}
            @Override public void onStartTrackingTouch(SeekBar s) {}
        });
    }
}
```

